perform:
if (object.id !== 'portable:steaming-mug-of-glow') {
  return lib.result("You can't drink that.");
}

var events = [
  lib.moveEvent(object.id, { to: 'void', from: player.id, description: 'Consumed neon infusion' }),
  lib.setEvent(player.id, { property: 'lit', value: true, description: 'Player is now glowing' })
];

return {
  output: "The liquid is thick and tastes of citrus and static. As you finish the mug, you notice a soft yellow light beginning to pulse beneath the skin of your hands. You have become your own light source, which is certainly one way to save on candles.",
  events: events
};

var carried = lib.carried();
var chisel = carried.find(function(e) { return e.id.includes('chisel') || e.tags.has('tool') && e.properties.name.toLowerCase().includes('chisel'); });

if (!chisel) {
  return lib.result("You'd need a chisel or a similar masonry tool to make any mark on the heavy stone basin.");
}

return lib.result("You tap the chisel against the rim of the vat. A small flake of stone skitters into the frothy gray liquid and is immediately swallowed by the abrasive foam. The masons nearby don't even look up.");
